import{j as a,b as e,c as i,aa as l}from"./chunks/framework.Bxf40uRC.js";const P=JSON.parse('{"title":"面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/面试问题.md","filePath":"计算机网络/面试问题.md","lastUpdated":null}'),t={name:"计算机网络/面试问题.md"},o=l(`<h1 id="面试问题" tabindex="-1">面试问题 <a class="header-anchor" href="#面试问题" aria-label="Permalink to &quot;面试问题&quot;">​</a></h1><p><img src="https://s2.loli.net/2024/03/17/fBW4uYZk38LHUzQ.png" alt="osi七层模型2"></p><p><img src="https://s2.loli.net/2024/04/10/tevc8z5sXbKV7hW.png" alt="TCP/IP 四层模型"></p><h2 id="客户端挂了的话-后续流程怎么处理" tabindex="-1">客户端挂了的话，后续流程怎么处理？ <a class="header-anchor" href="#客户端挂了的话-后续流程怎么处理" aria-label="Permalink to &quot;客户端挂了的话，后续流程怎么处理？&quot;">​</a></h2><h2 id="tcp状态码之4xx-和5xx" tabindex="-1">tcp状态码之4xx 和5xx? <a class="header-anchor" href="#tcp状态码之4xx-和5xx" aria-label="Permalink to &quot;tcp状态码之4xx 和5xx?&quot;">​</a></h2><p>200:请求成功：服务器已经成功处理了请求；</p><p>201:资源已创建：请求成功，并且服务器创建了新的资源；</p><p>202:已接受：请求已接受，但是尚未处理：</p><p>301：永久重定向：请求网页已经永久移动到新的位置；</p><p>302：临时重定向：说明请求的资源还在，但暂时需要用另一个URL来访问；</p><p>304：未修改：自从上次请求后，请求的网页未修改过，服务器返回此响应时，不会返回网页内容，重定向到已经存在的缓存文件中；</p><p>400：请求错误：入参有问题</p><p>401：未认证：请求要身份认证，对于需要登陆的网页，服务器返回此响应；</p><p>402：需要付费</p><p>403：禁止访问：服务器拒绝请求；</p><p>404：页面没找到：Not Found；</p><p>405：请求资源方式不允许：Post请求了一个Get接口；</p><p>500：服务器内部错误：服务里内部逻辑存在问题；</p><p>501：尚未实施：服务器不具备完成请求的功能；</p><p>502：错误网关：服务器作为网关或者代理，从上游服务器收到无效响应；</p><p>503：服务不可用：停机维护，暂时的状态；</p><p>504：网关超时：服务器作为网关代理，但是没有及时从上游服务器收到请求；</p><h2 id="session-存在于哪里-说说cookie-和-token" tabindex="-1">session 存在于哪里？说说cookie 和 token？ <a class="header-anchor" href="#session-存在于哪里-说说cookie-和-token" aria-label="Permalink to &quot;session  存在于哪里？说说cookie 和 token？&quot;">​</a></h2><p><a href="https://sloving.top/blogs/Note/chushiJWT.html" target="_blank" rel="noreferrer">https://sloving.top/blogs/Note/chushiJWT.html</a></p><ol><li><p>session存在于服务器；session 是另一种记录服务器和客户端会话状态的机制；</p></li><li><p>cookie是服务器发送给浏览器的小块数据，里面可能包含session_id，浏览器下次再次访问服务器时，如果在一个域下，就会自动携带cookie，做一些登录校验，信息共享等功能；分为会话cookie和持久cookie；</p></li><li><p>token是一种凭证，访问对应的资源接口；一般由 user_id + time + (权限范围) + (签名)组成；一般是用户通过账号密码登录后，服务器端验证无问题生成的，返回到浏览器，存储在cookie或者localstorage中；</p></li><li><p>jwt: token的一种，header + payload + signature组成，相比token，访问服务器，验证过程，获取用户信息等过程更加方便，而且能够解决跨域，csrf攻击；</p></li></ol><h2 id="socket服务器和客户端工作流程" tabindex="-1">socket服务器和客户端工作流程? <a class="header-anchor" href="#socket服务器和客户端工作流程" aria-label="Permalink to &quot;socket服务器和客户端工作流程?&quot;">​</a></h2><h3 id="服务器端的工作流程" tabindex="-1">服务器端的工作流程 <a class="header-anchor" href="#服务器端的工作流程" aria-label="Permalink to &quot;服务器端的工作流程&quot;">​</a></h3><ol><li>创建socket：服务器端会先创建一个socket，用于监听来自客户端的连接请求；</li><li>bind：服务器端将socket绑定到一个指定的网络地址和端口，从而监听来自于这个地址和端口的请求；</li><li>Listen：监听绑定地址上的请求，等待客户端的连接请求；</li><li>accept：接受连接，当一个客户端请求连接的时候，服务器端的socket接受请求并建立一个新的socket连接，专门用于与该客户端进行通信；</li><li>数据交换：一旦建立连接，服务器端就可以通过新建立的socket与客户端进行数据读写操作；</li><li>关闭连接：数据交换完成后，服务器端关闭与客户端的连接。服务器可以继续监听其他客户端的连接请求；</li></ol><h3 id="客户端的工作流程" tabindex="-1">客户端的工作流程 <a class="header-anchor" href="#客户端的工作流程" aria-label="Permalink to &quot;客户端的工作流程&quot;">​</a></h3><ol><li>创建Socket：客户端创建一个socket，用于与服务器端的socket进行连接；</li><li>connect：客户端的socket尝试连接服务器端的socket，需要指定服务器的网络地址和端口号；</li><li>数据交换；</li><li>关闭连接；</li></ol><h2 id="https的ssl-tsl握手流程" tabindex="-1">https的SSL/TSL握手流程 <a class="header-anchor" href="#https的ssl-tsl握手流程" aria-label="Permalink to &quot;https的SSL/TSL握手流程&quot;">​</a></h2><p><img src="https://s2.loli.net/2024/03/30/PCoZGvzRjJ1IFhK.png" alt="img"></p><h2 id="web接口比较慢-有哪些方式进行排查" tabindex="-1">web接口比较慢，有哪些方式进行排查？ <a class="header-anchor" href="#web接口比较慢-有哪些方式进行排查" aria-label="Permalink to &quot;web接口比较慢，有哪些方式进行排查？&quot;">​</a></h2><h4 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h4><ol><li>检查网络：通过ping或者traceroute命令检查网络连接状态</li><li>资源加载：是否存在大量的前端资源加载问题</li></ol><h4 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h4><ol><li>慢查询优化：开启数据库的慢查询日志功能，分析执行时间长的SQL查询，并进行优化。</li><li>索引优化：是否对常用的key进行建立索引，或者查询是否走了索引? 采用explain命令查看详细信息</li><li>优化sql查询：比如select * 这种尽量不要存在</li></ol><h4 id="服务器配置资源" tabindex="-1">服务器配置资源 <a class="header-anchor" href="#服务器配置资源" aria-label="Permalink to &quot;服务器配置资源&quot;">​</a></h4><ol><li>CPU和内存是否过大，是否存在资源的限制，通过TOP可以查询，P是按照CPU占用率倒序，M是内存倒序</li></ol><h4 id="应用程序" tabindex="-1">应用程序 <a class="header-anchor" href="#应用程序" aria-label="Permalink to &quot;应用程序&quot;">​</a></h4><ol><li>代码程序复杂度是否过高，可以通过一些代码分析工具分析哪些代码执行时间长；</li><li>是否存在并发逻辑问题；</li></ol><h2 id="没有建立连接-客户端直接发送数据给客户端会发生什么" tabindex="-1">没有建立连接，客户端直接发送数据给客户端会发生什么？ <a class="header-anchor" href="#没有建立连接-客户端直接发送数据给客户端会发生什么" aria-label="Permalink to &quot;没有建立连接，客户端直接发送数据给客户端会发生什么？&quot;">​</a></h2><p>如果没有建立连接，客户端尝试直接发送数据给服务器通常会导致以下几种情况，具体取决于所使用的通信协议：</p><h3 id="使用tcp协议" tabindex="-1">使用TCP协议 <a class="header-anchor" href="#使用tcp协议" aria-label="Permalink to &quot;使用TCP协议&quot;">​</a></h3><p>TCP（传输控制协议）是一种面向连接的协议，要求在数据传输之前必须建立连接。如果尝试在没有建立TCP连接的情况下发送数据：</p><ul><li><strong>连接未建立</strong>：客户端无法直接发送数据包给服务器，因为TCP协议要求在数据传输前通过三次握手过程建立连接。如果客户端尝试发送数据，操作系统通常会返回一个错误，提示没有建立连接。</li><li><strong>数据丢失</strong>：即使数据包被客户端强行发送出去，由于服务器端没有与之对应的连接状态，服务器将无法正确处理这些数据包，数据包会被服务器忽略或丢弃。</li></ul><h3 id="使用udp协议" tabindex="-1">使用UDP协议 <a class="header-anchor" href="#使用udp协议" aria-label="Permalink to &quot;使用UDP协议&quot;">​</a></h3><p>UDP（用户数据报协议）是一种无连接的协议，它允许数据包（数据报）在没有预先建立连接的情况下被发送。</p><ul><li><strong>数据可能到达</strong>：使用UDP，客户端可以在没有建立连接的情况下向服务器发送数据包。因为UDP不要求建立连接，数据包有可能到达服务器。</li><li><strong>无可靠性保证</strong>：UDP不保证数据包的到达顺序、可靠性或数据完整性。发送的数据可能会丢失、重复或乱序到达，而且UDP协议本身不提供重传机制或到达确认。</li></ul><h2 id="如果服务端向客户端发了多次请求得不到回应-断开连接之后-客户端再向服务端发请求-会收到怎样一个信息" tabindex="-1">如果服务端向客户端发了多次请求得不到回应，断开连接之后，客户端再向服务端发请求，会收到怎样一个信息？ <a class="header-anchor" href="#如果服务端向客户端发了多次请求得不到回应-断开连接之后-客户端再向服务端发请求-会收到怎样一个信息" aria-label="Permalink to &quot;如果服务端向客户端发了多次请求得不到回应，断开连接之后，客户端再向服务端发请求，会收到怎样一个信息？&quot;">​</a></h2><p>TCP: 收到RST报文</p><p>UDP: (当然这里已经明确指出了是断开连接了，所以应该是TCP连接)，如果是UDP的话，应该是没有响应，或者响应数据；</p><h2 id="四次挥手的目的" tabindex="-1">四次挥手的目的 <a class="header-anchor" href="#四次挥手的目的" aria-label="Permalink to &quot;四次挥手的目的&quot;">​</a></h2><ol><li>双方都可以主动的关闭连接</li><li>数据完整性和可靠性</li><li>防止旧的连接数据包干扰新连接</li></ol><h2 id="操作系统-有哪些具体服务可能是udp的" tabindex="-1">操作系统，有哪些具体服务可能是UDP的？ <a class="header-anchor" href="#操作系统-有哪些具体服务可能是udp的" aria-label="Permalink to &quot;操作系统，有哪些具体服务可能是UDP的？&quot;">​</a></h2><ol><li>DNS: 域名解析协议</li><li>SNMP: 简单网络管理协议</li><li>TFTP: 简单文件传输协议</li><li>RTP: 实时传输协议</li></ol><h2 id="tcp-keepalive机制的工作原理" tabindex="-1">TCP Keepalive机制的工作原理 <a class="header-anchor" href="#tcp-keepalive机制的工作原理" aria-label="Permalink to &quot;TCP Keepalive机制的工作原理&quot;">​</a></h2><ol><li><strong>启用Keepalive</strong>：在大多数操作系统中，TCP Keepalive默认可能是关闭的或者具有一个非常长的超时时间。应用程序可以通过设置socket选项来启用Keepalive，并配置相关参数，如探测间隔和探测次数。</li><li><strong>探测（Probe）发送</strong>：一旦Keepalive被启用，并且在配置的超时时间内没有在连接上检测到任何数据交换，操作系统将开始发送Keepalive探测。这些探测是特殊的TCP包，目的是检查对端是否仍然响应。</li><li><strong>响应检查</strong>：如果对端正常响应了Keepalive探测，表示连接仍然有效，操作系统将重置Keepalive计时器，并在下一个周期再次等待。如果对端没有响应，操作系统会继续发送探测，直到达到配置的探测次数限制。</li><li><strong>连接终止</strong>：如果所有Keepalive探测都没有得到响应，操作系统将认为连接已经断开，并通知应用程序。这通常通过在socket上报告一个错误来实现。</li></ol><h2 id="怎么解决tcp粘包问题" tabindex="-1">怎么解决TCP粘包问题？ <a class="header-anchor" href="#怎么解决tcp粘包问题" aria-label="Permalink to &quot;怎么解决TCP粘包问题？&quot;">​</a></h2><h3 id="_1、固定消息长度" tabindex="-1">1、固定消息长度 <a class="header-anchor" href="#_1、固定消息长度" aria-label="Permalink to &quot;1、固定消息长度&quot;">​</a></h3><p>和UDP操作方式相同，规定每个发送的消息的长度都是一致的，当接收方接收到这个长度的消息的时候，就认为这是一个有效的消息；</p><p>缺点：不够灵活，实际不常用</p><h3 id="_2、特殊字符当作边界" tabindex="-1">2、特殊字符当作边界 <a class="header-anchor" href="#_2、特殊字符当作边界" aria-label="Permalink to &quot;2、特殊字符当作边界&quot;">​</a></h3><p>可以在两个用户消息之间插入一个特殊的字符串，这样接收方在接收数据时，读到了这个字符串，就代表已经读完了一个完整的消息；</p><p>HTTP就是一个非常好的例子;</p><p><img src="https://s2.loli.net/2024/04/16/LQ1y3JwdEpPl7kx.png" alt="图片"></p><p>HTTP 通过设置回车符、换行符作为 HTTP 报文协议的边界。</p><p>有一点要注意，这个作为边界点的特殊字符，如果刚好消息内容里有这个特殊字符，我们要对这个字符转义，避免被接收方当作消息的边界点而解析到无效的数据</p><h3 id="_3、自定义消息结构" tabindex="-1">3、自定义消息结构 <a class="header-anchor" href="#_3、自定义消息结构" aria-label="Permalink to &quot;3、自定义消息结构&quot;">​</a></h3><p>我们可以自定义一个消息结构，由包头和数据组成，其中包头是固定大小的，包头里面有一个字段可以指定后续数据有多大；</p><div class="language-c++ vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c++</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    u_int32_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> message_length; </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    char</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> message_data[]; </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} message;</span></span></code></pre></div>`,71),s=[o];function r(n,h,p,c,d,k){return e(),i("div",null,s)}const b=a(t,[["render",r]]);export{P as __pageData,b as default};
